int find_maximum(int a[], int n, int k) {
    std::unordered_map<int, int> b;
    for (int i = 0; i < n; i++) {
        int x = a[i];
        int d = std::min(1 + i, n - i);
        if (!b.count(x)) b[x] = d;
        else {
            b[x] = std::min(d, b[x]);
        }
    }
    int ans = std::numeric_limits<int>::max();
    for (int i = 0; i < n; i++) {
        int x = a[i];
        if (x != k - x && b.count(k - x)) ans = std::min(std::max(b[x], b[k - x]), ans);
    }
    return ans;
}

